//! NIST SP 800-89 — Recommendation for Obtaining Assurances for
//! Digital Signature Applications
//!
//! Validates that digital signature operations use approved parameters
//! before signing, providing assurance that:
//!
//! 1. The signing algorithm is approved for the intended use
//! 2. Key size meets minimum strength requirements
//! 3. Hash algorithm is appropriate for the signing algorithm
//! 4. The signing key is in a valid state for signing
//!
//! ## SP 800-89 §3 — Assurance of Signature Validity
//!
//! A signature is considered valid only if:
//! - The algorithm is approved (FIPS 186-5, SP 800-131A)
//! - The key pair was generated by an approved method
//! - The hash function is approved (FIPS 180-4 SHA-2, FIPS 202 SHA-3)
//! - The key length provides adequate security strength
//!
//! ## References
//!
//! - NIST SP 800-89 (2006, Rev 2013)
//! - NIST SP 800-131A Rev 2 (Transitioning the Use of Cryptographic Algorithms)
//! - FIPS 186-5 (Digital Signature Standard)
//! - NIST SP 800-57 Part 1 Rev 5 (Key Management: General)

use crate::algo::AlgorithmId;

/// Minimum security strength in bits per NIST SP 800-57 Table 2.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum SecurityStrength {
    /// 112 bits (RSA-2048, ECDSA P-224) — legacy, disallowed after 2030
    Bits112,
    /// 128 bits (RSA-3072, ECDSA P-256, AES-128)
    Bits128,
    /// 192 bits (RSA-7680, ECDSA P-384, AES-192)
    Bits192,
    /// 256 bits (RSA-15360, ECDSA P-521, AES-256)
    Bits256,
}

impl SecurityStrength {
    /// Numeric value in bits.
    pub fn bits(self) -> u32 {
        match self {
            Self::Bits112 => 112,
            Self::Bits128 => 128,
            Self::Bits192 => 192,
            Self::Bits256 => 256,
        }
    }
}

impl std::fmt::Display for SecurityStrength {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}-bit", self.bits())
    }
}

/// Pre-signing validation result.
#[derive(Debug, Clone)]
pub struct SignatureAssurance {
    /// Whether the signing operation is approved.
    pub approved: bool,
    /// Security strength of the signing algorithm.
    pub strength: SecurityStrength,
    /// Approved hash algorithms for this key type.
    pub approved_hashes: Vec<&'static str>,
    /// Findings from the validation.
    pub findings: Vec<AssuranceFinding>,
}

/// A single finding from pre-signing validation.
#[derive(Debug, Clone)]
pub struct AssuranceFinding {
    /// Finding code (e.g., "SIG-001").
    pub code: &'static str,
    /// Whether this finding is a pass or failure.
    pub pass: bool,
    /// Description of the check.
    pub description: String,
    /// Reference to the governing standard.
    pub reference: &'static str,
}

/// Validate a signing algorithm before use per SP 800-89.
///
/// Checks that the algorithm, key size, and associated parameters are
/// approved for digital signature generation. This should be called
/// before every signing operation as part of the assurance framework.
///
/// # Parameters
///
/// - `algorithm` — The signing algorithm to validate
/// - `require_post_2030` — If true, enforces SP 800-131A Rev 2 post-2030 requirements
///   (minimum 128-bit security strength, no RSA-2048)
///
/// # Returns
///
/// A `SignatureAssurance` struct with detailed findings.
pub fn validate_signing_parameters(
    algorithm: AlgorithmId,
    require_post_2030: bool,
) -> SignatureAssurance {
    let mut findings = Vec::new();

    // SIG-001: Algorithm is an approved digital signature algorithm
    let (approved_algo, strength, approved_hashes) = algorithm_properties(&algorithm);

    findings.push(AssuranceFinding {
        code: "SIG-001",
        pass: approved_algo,
        description: format!(
            "Algorithm {} is {}an approved digital signature algorithm (FIPS 186-5)",
            algorithm,
            if approved_algo { "" } else { "NOT " }
        ),
        reference: "SP 800-89 §3.1; FIPS 186-5 §3",
    });

    // SIG-002: Key length provides adequate security strength
    let min_strength = if require_post_2030 {
        SecurityStrength::Bits128
    } else {
        SecurityStrength::Bits112
    };

    let adequate_strength = strength >= min_strength;
    findings.push(AssuranceFinding {
        code: "SIG-002",
        pass: adequate_strength,
        description: format!(
            "Algorithm {} provides {}-bit security (minimum: {}-bit{})",
            algorithm,
            strength.bits(),
            min_strength.bits(),
            if require_post_2030 {
                ", post-2030 requirement"
            } else {
                ""
            }
        ),
        reference: "SP 800-131A Rev 2 §2; SP 800-57 Pt.1 Table 2",
    });

    // SIG-003: Hash function is approved for this algorithm
    // Algorithms with built-in hashes (ML-DSA, SLH-DSA, EdDSA) pass this check
    // because their internal hash is part of the approved algorithm specification.
    let has_builtin_hash = has_builtin_hash_fn(&algorithm);
    let has_approved_hash = !approved_hashes.is_empty() || has_builtin_hash;
    findings.push(AssuranceFinding {
        code: "SIG-003",
        pass: has_approved_hash,
        description: format!(
            "Approved hash algorithms for {}: {}",
            algorithm,
            if approved_hashes.is_empty() {
                "built-in (algorithm defines its own approved hash)".to_string()
            } else {
                approved_hashes.join(", ")
            }
        ),
        reference: "FIPS 180-4 (SHA-2); FIPS 202 (SHA-3); FIPS 204 (ML-DSA); FIPS 205 (SLH-DSA)",
    });

    // SIG-004: Algorithm is not deprecated for new signatures
    let not_deprecated = !is_deprecated_for_signing(&algorithm);
    findings.push(AssuranceFinding {
        code: "SIG-004",
        pass: not_deprecated,
        description: format!(
            "Algorithm {} is {}deprecated for new digital signatures",
            algorithm,
            if not_deprecated { "NOT " } else { "" }
        ),
        reference: "SP 800-131A Rev 2 §4",
    });

    let approved = approved_algo && adequate_strength && has_approved_hash && not_deprecated;

    SignatureAssurance {
        approved,
        strength,
        approved_hashes,
        findings,
    }
}

/// Get the security properties for a given algorithm.
///
/// Returns (is_approved, security_strength, approved_hash_algorithms).
fn algorithm_properties(algo: &AlgorithmId) -> (bool, SecurityStrength, Vec<&'static str>) {
    match algo {
        // ECDSA — FIPS 186-5 §6
        AlgorithmId::EcdsaP256 => (
            true,
            SecurityStrength::Bits128,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),
        AlgorithmId::EcdsaP384 => (true, SecurityStrength::Bits192, vec!["SHA-384", "SHA-512"]),

        // RSA PKCS#1 v1.5 — FIPS 186-5 §5
        AlgorithmId::Rsa2048 => (
            true,
            SecurityStrength::Bits112,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),
        AlgorithmId::Rsa3072 => (
            true,
            SecurityStrength::Bits128,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),
        AlgorithmId::Rsa4096 => (
            true,
            SecurityStrength::Bits128,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),

        // RSA-PSS — FIPS 186-5 §5, SP 800-131A preferred
        AlgorithmId::Rsa3072Pss => (
            true,
            SecurityStrength::Bits128,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),
        AlgorithmId::Rsa4096Pss => (
            true,
            SecurityStrength::Bits128,
            vec!["SHA-256", "SHA-384", "SHA-512"],
        ),

        // EdDSA — RFC 8032, not FIPS-approved but increasingly adopted
        AlgorithmId::Ed25519 => (
            false, // Not FIPS-approved (as of 2026)
            SecurityStrength::Bits128,
            vec![], // EdDSA uses built-in SHA-512
        ),

        // PQC — FIPS 204/205 (standardized, awaiting CMVP validation)
        #[cfg(feature = "pqc")]
        AlgorithmId::MlDsa44 => (
            true, // FIPS 204 approved
            SecurityStrength::Bits128,
            vec![], // ML-DSA uses internal SHAKE-256
        ),
        #[cfg(feature = "pqc")]
        AlgorithmId::MlDsa65 => (true, SecurityStrength::Bits192, vec![]),
        #[cfg(feature = "pqc")]
        AlgorithmId::MlDsa87 => (true, SecurityStrength::Bits256, vec![]),
        #[cfg(feature = "pqc")]
        AlgorithmId::SlhDsaSha2_128s => (
            true, // FIPS 205 approved
            SecurityStrength::Bits128,
            vec![], // SLH-DSA uses internal SHA-256
        ),
        #[cfg(feature = "pqc")]
        AlgorithmId::SlhDsaSha2_192s => (true, SecurityStrength::Bits192, vec![]),
        #[cfg(feature = "pqc")]
        AlgorithmId::SlhDsaSha2_256s => (true, SecurityStrength::Bits256, vec![]),

        // Composite — no standalone FIPS approval
        #[cfg(feature = "pqc")]
        AlgorithmId::MlDsa44EcdsaP256
        | AlgorithmId::MlDsa65EcdsaP256
        | AlgorithmId::MlDsa65EcdsaP384
        | AlgorithmId::MlDsa87EcdsaP384 => (
            false, // No FIPS validation path for composites
            SecurityStrength::Bits128,
            vec![],
        ),
    }
}

/// Check if an algorithm is deprecated for new digital signatures.
///
/// Per SP 800-131A Rev 2, certain algorithms are deprecated even though
/// they may still be used for verification of existing signatures.
fn is_deprecated_for_signing(algo: &AlgorithmId) -> bool {
    matches!(
        algo,
        // RSA-2048 is deprecated for new signatures per SP 800-131A Rev 2
        // (acceptable for verification only after 2030)
        AlgorithmId::Rsa2048
    )
}

/// Check if an algorithm uses a built-in hash function.
///
/// Algorithms like ML-DSA (SHAKE-256), SLH-DSA (SHA-256), and EdDSA (SHA-512)
/// define their own hash function as part of the algorithm specification.
/// These algorithms pass SIG-003 even though they don't accept external hash
/// algorithm selection.
fn has_builtin_hash_fn(algo: &AlgorithmId) -> bool {
    match algo {
        AlgorithmId::Ed25519 => true,
        #[cfg(feature = "pqc")]
        AlgorithmId::MlDsa44
        | AlgorithmId::MlDsa65
        | AlgorithmId::MlDsa87
        | AlgorithmId::SlhDsaSha2_128s
        | AlgorithmId::SlhDsaSha2_192s
        | AlgorithmId::SlhDsaSha2_256s
        | AlgorithmId::MlDsa44EcdsaP256
        | AlgorithmId::MlDsa65EcdsaP256
        | AlgorithmId::MlDsa65EcdsaP384
        | AlgorithmId::MlDsa87EcdsaP384 => true,
        _ => false,
    }
}

/// Quick check: is this algorithm approved for signing per SP 800-89?
///
/// Convenience function that returns true/false without detailed findings.
pub fn is_approved_for_signing(algorithm: AlgorithmId) -> bool {
    let (approved, _, _) = algorithm_properties(&algorithm);
    approved && !is_deprecated_for_signing(&algorithm)
}

/// Get the security strength of an algorithm in bits.
pub fn algorithm_security_strength(algorithm: &AlgorithmId) -> u32 {
    let (_, strength, _) = algorithm_properties(algorithm);
    strength.bits()
}

/// Hash algorithm identifier for pre-signing validation.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HashAlgorithm {
    Sha256,
    Sha384,
    Sha512,
}

impl HashAlgorithm {
    /// The hash name as used in approved_hashes lists.
    pub fn name(self) -> &'static str {
        match self {
            Self::Sha256 => "SHA-256",
            Self::Sha384 => "SHA-384",
            Self::Sha512 => "SHA-512",
        }
    }

    /// Output size in bits.
    pub fn output_bits(self) -> u32 {
        match self {
            Self::Sha256 => 256,
            Self::Sha384 => 384,
            Self::Sha512 => 512,
        }
    }
}

impl std::fmt::Display for HashAlgorithm {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.name())
    }
}

/// Validate that a specific hash algorithm is approved for use with a signing algorithm.
///
/// Per FIPS 180-4 and FIPS 186-5, the hash function must be appropriate for
/// the signing algorithm's security strength. For example:
/// - ECDSA P-384 requires SHA-384 or SHA-512 (SHA-256 is too weak)
/// - RSA algorithms accept SHA-256, SHA-384, SHA-512
/// - PQC/EdDSA algorithms use built-in hashes (any external hash is rejected)
///
/// Returns Ok(()) if the hash is approved, or an error describing the mismatch.
pub fn validate_hash_for_algorithm(
    algorithm: &AlgorithmId,
    hash: HashAlgorithm,
) -> Result<(), String> {
    if has_builtin_hash_fn(algorithm) {
        return Err(format!(
            "Algorithm {} uses a built-in hash function; external hash {} is not applicable",
            algorithm, hash
        ));
    }

    let (_, _, approved_hashes) = algorithm_properties(algorithm);

    if approved_hashes.contains(&hash.name()) {
        Ok(())
    } else {
        Err(format!(
            "Hash {} is not approved for {}; approved hashes: {}",
            hash,
            algorithm,
            if approved_hashes.is_empty() {
                "none (algorithm uses built-in hash)".to_string()
            } else {
                approved_hashes.join(", ")
            }
        ))
    }
}

/// RSA signature padding scheme.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RsaPadding {
    /// RSASSA-PKCS1-v1_5 (RFC 8017 §8.2) — legacy
    Pkcs1v15,
    /// RSASSA-PSS (RFC 8017 §8.1) — preferred per SP 800-131A
    Pss,
}

impl std::fmt::Display for RsaPadding {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Pkcs1v15 => write!(f, "RSASSA-PKCS1-v1_5"),
            Self::Pss => write!(f, "RSASSA-PSS"),
        }
    }
}

/// Check if RSA-PSS padding is being used for a given algorithm.
///
/// Per SP 800-131A Rev 2, RSA-PSS is preferred over PKCS#1 v1.5 for new
/// signatures. This function identifies which padding the algorithm uses.
pub fn rsa_padding_for_algorithm(algorithm: &AlgorithmId) -> Option<RsaPadding> {
    match algorithm {
        AlgorithmId::Rsa2048 | AlgorithmId::Rsa3072 | AlgorithmId::Rsa4096 => {
            Some(RsaPadding::Pkcs1v15)
        }
        AlgorithmId::Rsa3072Pss | AlgorithmId::Rsa4096Pss => Some(RsaPadding::Pss),
        _ => None, // Not an RSA algorithm
    }
}

/// Validate RSA padding selection per SP 800-131A Rev 2.
///
/// Returns findings about whether the selected padding scheme meets
/// current and future requirements.
///
/// - `strict`: If true, PKCS#1 v1.5 is rejected (post-2030 requirement)
/// - `false`: PKCS#1 v1.5 is allowed with a warning
pub fn validate_rsa_padding(padding: RsaPadding, strict: bool) -> AssuranceFinding {
    match (padding, strict) {
        (RsaPadding::Pss, _) => AssuranceFinding {
            code: "SIG-005",
            pass: true,
            description: "RSA-PSS padding is the preferred scheme per SP 800-131A Rev 2"
                .to_string(),
            reference: "SP 800-131A Rev 2 §2; RFC 8017 §8.1",
        },
        (RsaPadding::Pkcs1v15, false) => AssuranceFinding {
            code: "SIG-005",
            pass: true,
            description:
                "RSASSA-PKCS1-v1_5 is acceptable pre-2030 but PSS is preferred per SP 800-131A"
                    .to_string(),
            reference: "SP 800-131A Rev 2 §2; RFC 8017 §8.2",
        },
        (RsaPadding::Pkcs1v15, true) => AssuranceFinding {
            code: "SIG-005",
            pass: false,
            description:
                "RSASSA-PKCS1-v1_5 is disallowed in strict mode; use RSA-PSS per SP 800-131A"
                    .to_string(),
            reference: "SP 800-131A Rev 2 §4",
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_ecdsa_p256_approved() {
        let result = validate_signing_parameters(AlgorithmId::EcdsaP256, false);
        assert!(result.approved);
        assert_eq!(result.strength, SecurityStrength::Bits128);
        assert!(result.approved_hashes.contains(&"SHA-256"));
        assert!(result.findings.iter().all(|f| f.pass));
    }

    #[test]
    fn test_ecdsa_p384_approved() {
        let result = validate_signing_parameters(AlgorithmId::EcdsaP384, false);
        assert!(result.approved);
        assert_eq!(result.strength, SecurityStrength::Bits192);
        assert!(!result.approved_hashes.contains(&"SHA-256")); // SHA-256 too weak for P-384
        assert!(result.approved_hashes.contains(&"SHA-384"));
    }

    #[test]
    fn test_rsa_2048_deprecated() {
        let result = validate_signing_parameters(AlgorithmId::Rsa2048, false);
        // RSA-2048 is approved but deprecated for new signatures
        assert!(!result.approved);
        let sig004 = result
            .findings
            .iter()
            .find(|f| f.code == "SIG-004")
            .unwrap();
        assert!(!sig004.pass);
    }

    #[test]
    fn test_rsa_2048_fails_post_2030() {
        let result = validate_signing_parameters(AlgorithmId::Rsa2048, true);
        assert!(!result.approved);
        let sig002 = result
            .findings
            .iter()
            .find(|f| f.code == "SIG-002")
            .unwrap();
        assert!(!sig002.pass); // 112-bit < 128-bit minimum
    }

    #[test]
    fn test_rsa_3072_approved() {
        let result = validate_signing_parameters(AlgorithmId::Rsa3072, true);
        assert!(result.approved);
        assert_eq!(result.strength, SecurityStrength::Bits128);
    }

    #[test]
    fn test_rsa_4096_approved() {
        let result = validate_signing_parameters(AlgorithmId::Rsa4096, false);
        assert!(result.approved);
    }

    #[test]
    fn test_rsa_pss_preferred() {
        let result = validate_signing_parameters(AlgorithmId::Rsa3072Pss, true);
        assert!(result.approved);

        let result4096 = validate_signing_parameters(AlgorithmId::Rsa4096Pss, true);
        assert!(result4096.approved);
    }

    #[test]
    fn test_ed25519_not_fips_approved() {
        let result = validate_signing_parameters(AlgorithmId::Ed25519, false);
        assert!(!result.approved);
        let sig001 = result
            .findings
            .iter()
            .find(|f| f.code == "SIG-001")
            .unwrap();
        assert!(!sig001.pass);
    }

    #[test]
    #[cfg(feature = "pqc")]
    fn test_ml_dsa_approved() {
        let r44 = validate_signing_parameters(AlgorithmId::MlDsa44, false);
        assert!(r44.approved);
        assert_eq!(r44.strength, SecurityStrength::Bits128);

        let r65 = validate_signing_parameters(AlgorithmId::MlDsa65, false);
        assert!(r65.approved);
        assert_eq!(r65.strength, SecurityStrength::Bits192);

        let r87 = validate_signing_parameters(AlgorithmId::MlDsa87, false);
        assert!(r87.approved);
        assert_eq!(r87.strength, SecurityStrength::Bits256);
    }

    #[test]
    #[cfg(feature = "pqc")]
    fn test_slh_dsa_approved() {
        let r128 = validate_signing_parameters(AlgorithmId::SlhDsaSha2_128s, false);
        assert!(r128.approved);

        let r192 = validate_signing_parameters(AlgorithmId::SlhDsaSha2_192s, false);
        assert!(r192.approved);
        assert_eq!(r192.strength, SecurityStrength::Bits192);

        let r256 = validate_signing_parameters(AlgorithmId::SlhDsaSha2_256s, false);
        assert!(r256.approved);
        assert_eq!(r256.strength, SecurityStrength::Bits256);
    }

    #[test]
    #[cfg(feature = "pqc")]
    fn test_composite_not_fips_approved() {
        let result = validate_signing_parameters(AlgorithmId::MlDsa44EcdsaP256, false);
        assert!(!result.approved);
    }

    #[test]
    fn test_is_approved_for_signing_convenience() {
        assert!(is_approved_for_signing(AlgorithmId::EcdsaP256));
        assert!(is_approved_for_signing(AlgorithmId::Rsa3072));
        assert!(!is_approved_for_signing(AlgorithmId::Rsa2048)); // Deprecated
        assert!(!is_approved_for_signing(AlgorithmId::Ed25519)); // Not FIPS
    }

    #[test]
    fn test_algorithm_security_strength() {
        assert_eq!(algorithm_security_strength(&AlgorithmId::EcdsaP256), 128);
        assert_eq!(algorithm_security_strength(&AlgorithmId::EcdsaP384), 192);
        assert_eq!(algorithm_security_strength(&AlgorithmId::Rsa2048), 112);
        assert_eq!(algorithm_security_strength(&AlgorithmId::Rsa3072), 128);
        assert_eq!(algorithm_security_strength(&AlgorithmId::Rsa4096), 128);
    }

    #[test]
    fn test_security_strength_ordering() {
        assert!(SecurityStrength::Bits112 < SecurityStrength::Bits128);
        assert!(SecurityStrength::Bits128 < SecurityStrength::Bits192);
        assert!(SecurityStrength::Bits192 < SecurityStrength::Bits256);
    }

    #[test]
    fn test_security_strength_display() {
        assert_eq!(SecurityStrength::Bits128.to_string(), "128-bit");
        assert_eq!(SecurityStrength::Bits256.to_string(), "256-bit");
    }

    // ---- Hash-algorithm validation tests (FIPS 180-4 / 186-5) ----

    #[test]
    fn test_hash_p256_sha256_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::EcdsaP256, HashAlgorithm::Sha256).is_ok()
        );
    }

    #[test]
    fn test_hash_p256_sha384_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::EcdsaP256, HashAlgorithm::Sha384).is_ok()
        );
    }

    #[test]
    fn test_hash_p256_sha512_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::EcdsaP256, HashAlgorithm::Sha512).is_ok()
        );
    }

    #[test]
    fn test_hash_p384_sha256_rejected() {
        let result = validate_hash_for_algorithm(&AlgorithmId::EcdsaP384, HashAlgorithm::Sha256);
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("not approved"));
    }

    #[test]
    fn test_hash_p384_sha384_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::EcdsaP384, HashAlgorithm::Sha384).is_ok()
        );
    }

    #[test]
    fn test_hash_p384_sha512_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::EcdsaP384, HashAlgorithm::Sha512).is_ok()
        );
    }

    #[test]
    fn test_hash_rsa3072_all_approved() {
        assert!(validate_hash_for_algorithm(&AlgorithmId::Rsa3072, HashAlgorithm::Sha256).is_ok());
        assert!(validate_hash_for_algorithm(&AlgorithmId::Rsa3072, HashAlgorithm::Sha384).is_ok());
        assert!(validate_hash_for_algorithm(&AlgorithmId::Rsa3072, HashAlgorithm::Sha512).is_ok());
    }

    #[test]
    fn test_hash_rsa_pss_all_approved() {
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::Rsa3072Pss, HashAlgorithm::Sha256).is_ok()
        );
        assert!(
            validate_hash_for_algorithm(&AlgorithmId::Rsa4096Pss, HashAlgorithm::Sha384).is_ok()
        );
    }

    #[test]
    fn test_hash_ed25519_builtin_rejects_external() {
        let result = validate_hash_for_algorithm(&AlgorithmId::Ed25519, HashAlgorithm::Sha256);
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("built-in hash"));
    }

    #[test]
    fn test_hash_algorithm_display() {
        assert_eq!(HashAlgorithm::Sha256.to_string(), "SHA-256");
        assert_eq!(HashAlgorithm::Sha384.to_string(), "SHA-384");
        assert_eq!(HashAlgorithm::Sha512.to_string(), "SHA-512");
    }

    #[test]
    fn test_hash_algorithm_output_bits() {
        assert_eq!(HashAlgorithm::Sha256.output_bits(), 256);
        assert_eq!(HashAlgorithm::Sha384.output_bits(), 384);
        assert_eq!(HashAlgorithm::Sha512.output_bits(), 512);
    }

    // ---- RSA padding preference tests (SP 800-131A) ----

    #[test]
    fn test_rsa_padding_pss_always_approved() {
        let finding = validate_rsa_padding(RsaPadding::Pss, false);
        assert!(finding.pass);
        assert_eq!(finding.code, "SIG-005");
        let strict_finding = validate_rsa_padding(RsaPadding::Pss, true);
        assert!(strict_finding.pass);
    }

    #[test]
    fn test_rsa_padding_pkcs1_pre2030_approved() {
        let finding = validate_rsa_padding(RsaPadding::Pkcs1v15, false);
        assert!(finding.pass);
        assert!(finding.description.contains("acceptable"));
    }

    #[test]
    fn test_rsa_padding_pkcs1_strict_rejected() {
        let finding = validate_rsa_padding(RsaPadding::Pkcs1v15, true);
        assert!(!finding.pass);
        assert!(finding.description.contains("disallowed"));
    }

    #[test]
    fn test_rsa_padding_for_algorithm() {
        assert_eq!(
            rsa_padding_for_algorithm(&AlgorithmId::Rsa3072),
            Some(RsaPadding::Pkcs1v15)
        );
        assert_eq!(
            rsa_padding_for_algorithm(&AlgorithmId::Rsa4096),
            Some(RsaPadding::Pkcs1v15)
        );
        assert_eq!(
            rsa_padding_for_algorithm(&AlgorithmId::Rsa3072Pss),
            Some(RsaPadding::Pss)
        );
        assert_eq!(
            rsa_padding_for_algorithm(&AlgorithmId::Rsa4096Pss),
            Some(RsaPadding::Pss)
        );
        assert_eq!(rsa_padding_for_algorithm(&AlgorithmId::EcdsaP256), None);
        assert_eq!(rsa_padding_for_algorithm(&AlgorithmId::Ed25519), None);
    }

    #[test]
    fn test_rsa_padding_display() {
        assert_eq!(RsaPadding::Pkcs1v15.to_string(), "RSASSA-PKCS1-v1_5");
        assert_eq!(RsaPadding::Pss.to_string(), "RSASSA-PSS");
    }

    #[test]
    fn test_all_findings_have_references() {
        let result = validate_signing_parameters(AlgorithmId::EcdsaP256, false);
        for finding in &result.findings {
            assert!(
                !finding.reference.is_empty(),
                "Finding {} missing reference",
                finding.code
            );
            assert!(
                !finding.description.is_empty(),
                "Finding {} missing description",
                finding.code
            );
        }
    }

    #[test]
    fn test_post_2030_enforcement() {
        // P-256 passes both pre and post 2030
        let pre = validate_signing_parameters(AlgorithmId::EcdsaP256, false);
        let post = validate_signing_parameters(AlgorithmId::EcdsaP256, true);
        assert!(pre.approved);
        assert!(post.approved);

        // RSA-3072 passes both
        let pre3072 = validate_signing_parameters(AlgorithmId::Rsa3072, false);
        let post3072 = validate_signing_parameters(AlgorithmId::Rsa3072, true);
        assert!(pre3072.approved);
        assert!(post3072.approved);
    }
}
